const headers = $input.first().json.headers;
const raw = headers['set-cookie'] || [];
const list = Array.isArray(raw) ? raw : [raw];
const cookie = list.map(c => c.split(';')[0]).join('; ');
return [{ json: { cookie } }];

const html = String($input.first().json);
const now = new Date().toISOString();
const emails = [...new Set((html.match(/[\w.+\-]+@[\w\-]+\.[a-z]{2,}/g) || []))]
  .filter(e => !e.includes('example') && !e.includes('n8n') && !e.includes('doctor'));
if (!emails.length) return [{ json: { error: 'Sin leads', timestamp: now } }];
return emails.map(email => ({ json: { email, scraped_at: now, source: 'CRM tracker.machukllc.xyz' } }));

