function b64url(obj) {
  return Buffer.from(typeof obj === 'string' ? obj : JSON.stringify(obj))
    .toString('base64')
    .replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
}

// Construir JWT para Google OAuth2
const now = Math.floor(Date.now()/1000);
const header  = { alg:'RS256', typ:'JWT' };
const payload = {
  iss: SA_EMAIL,
  scope: 'https://www.googleapis.com/auth/spreadsheets',
  aud: 'https://oauth2.googleapis.com/token',
  iat: now,
  exp: now + 3600
};
const toSign = b64url(header) + '.' + b64url(payload);
const sign = crypto.createSign('RSA-SHA256');
sign.update(toSign);
const sig = sign.sign(PRIVATE_KEY, 'base64')
  .replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
const jwt = toSign + '.' + sig;

// Pasar leads del nodo anterior junto con el JWT
const leads = $input.all().map(i => i.json);
return [{ json: { jwt, leads, sheetId: SHEET_ID } }];

// Intercambiar JWT por access token de Google
const { jwt, leads, sheetId } = $input.first().json;
const resp = await $helpers.httpRequest({
  method: 'POST',
  url: 'https://oauth2.googleapis.com/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=${jwt}`
});
return [{ json: { accessToken: resp.access_token, leads, sheetId } }];

// Insertar leads en Google Sheets via API REST
const { accessToken, leads, sheetId } = $input.first().json;
const headers = ['Email', 'Scrapeado', 'Fuente'];
const values = leads.map(l => [l.email || '', l.scraped_at || '', l.source || '']);

const resp = await $helpers.httpRequest({
  method: 'POST',
  url: `https://sheets.googleapis.com/v4/spreadsheets/${sheetId}/values/Sheet1!A1:append?valueInputOption=RAW&insertDataOption=INSERT_ROWS`,
  headers: {
    'Authorization': `Bearer ${accessToken}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({ values }),
  json: false
});

const result = typeof resp === 'string' ? JSON.parse(resp) : resp;
const updated = result.updates?.updatedRows || 0;
return [{ json: { success: true, rowsInserted: updated, timestamp: new Date().toISOString() } }];
